import{_ as r,o as a,c as o,ae as d}from"./chunks/framework.BeMCGcrk.js";const p=JSON.parse('{"title":"耐心套牢 · 每日投资复盘","description":"","frontmatter":{},"headers":[],"relativePath":"blog/2026-06-22-review-bottom-signals.md","filePath":"blog/2026-06-22-review-bottom-signals.md"}'),e={name:"blog/2026-06-22-review-bottom-signals.md"};function l(n,t,i,h,s,g){return a(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="耐心套牢-·-每日投资复盘" tabindex="-1">耐心套牢 · 每日投资复盘 <a class="header-anchor" href="#耐心套牢-·-每日投资复盘" aria-label="Permalink to &quot;耐心套牢 · 每日投资复盘&quot;">​</a></h1><p><strong>日期：</strong> 2026-06-22<br><strong>标签：</strong> 投资复盘 · 港股 · 市场底部信号</p><hr><h2 id="持仓情况观察" tabindex="-1">持仓情况观察 <a class="header-anchor" href="#持仓情况观察" aria-label="Permalink to &quot;持仓情况观察&quot;">​</a></h2><p>当前持仓以港股科技（恒生科技）为主，消费为辅。市场持续调整，持仓估值承压。</p><p>核心策略：<strong>耐心套牢</strong>——在底部信号明确出现之前，不轻易割肉，也不盲目补仓。</p><hr><h2 id="今日实时数据-2026-06-22-15-00" tabindex="-1">今日实时数据 (2026-06-22 15:00) <a class="header-anchor" href="#今日实时数据-2026-06-22-15-00" aria-label="Permalink to &quot;今日实时数据 (2026-06-22 15:00)&quot;">​</a></h2><h3 id="_1-成交地量监控" tabindex="-1">1. 成交地量监控 <a class="header-anchor" href="#_1-成交地量监控" aria-label="Permalink to &quot;1. 成交地量监控&quot;">​</a></h3><ul><li>上证指数收于 4163.10 点，涨 +1.78%</li><li>成交额约 7437 亿元（盘中数据）</li><li>注：2026年5月 A股日均成交额 2.66 万亿元，连续多日破 3 万亿，当前市场交投活跃，<strong>非地量区间</strong></li></ul><h3 id="_2-恒生科技估值" tabindex="-1">2. 恒生科技估值 <a class="header-anchor" href="#_2-恒生科技估值" aria-label="Permalink to &quot;2. 恒生科技估值&quot;">​</a></h3><table tabindex="0"><thead><tr><th>标的</th><th>当前价格</th><th>距52周高点</th><th>52周低位</th><th>距52周低点</th></tr></thead><tbody><tr><td>小米 (01810)</td><td>23.82 HKD</td><td>-61.24%</td><td>23.52 HKD</td><td>+1.28%</td></tr><tr><td>阿里 (09988)</td><td>103.40 HKD</td><td>-44.14%</td><td>100.77 HKD</td><td>+2.61%</td></tr><tr><td>恒科ETF (513180)</td><td>0.582 CNY</td><td>-35.04%</td><td>0.572 CNY</td><td>+1.75%</td></tr></tbody></table><h3 id="_3-白酒走势" tabindex="-1">3. 白酒走势 <a class="header-anchor" href="#_3-白酒走势" aria-label="Permalink to &quot;3. 白酒走势&quot;">​</a></h3><table tabindex="0"><thead><tr><th>标的</th><th>今日涨跌</th><th>52周高位</th><th>52周低位</th><th>距52周高点</th></tr></thead><tbody><tr><td>茅台</td><td>-9.86%</td><td>1568.00</td><td>1093.50</td><td>-15.89%</td></tr><tr><td>五粮液</td><td>-27.74%</td><td>129.27</td><td>68.27</td><td>-37.88%</td></tr></tbody></table><h3 id="_4-市场情绪" tabindex="-1">4. 市场情绪 <a class="header-anchor" href="#_4-市场情绪" aria-label="Permalink to &quot;4. 市场情绪&quot;">​</a></h3><ul><li><strong>新股民开户</strong>: 2026年5月新增 276.53 万户，同比暴增 77.76%（上交所数据）</li><li><strong>白酒行业</strong>: 86.7% 企业利润下滑，商务礼赠场景减少 82.8%（中酒协报告）</li></ul><hr><h2 id="见底信号监测清单" tabindex="-1">见底信号监测清单 <a class="header-anchor" href="#见底信号监测清单" aria-label="Permalink to &quot;见底信号监测清单&quot;">​</a></h2><blockquote><p>以下 6 个信号，基于今日数据逐一评估。信号越极致，距离底部越近。</p></blockquote><h3 id="_1-成交额持续萎缩-市场无人问津" tabindex="-1">① 成交额持续萎缩，市场无人问津 <a class="header-anchor" href="#_1-成交额持续萎缩-市场无人问津" aria-label="Permalink to &quot;① 成交额持续萎缩，市场无人问津&quot;">​</a></h3><p><strong>状态：</strong> ❌ 未出现</p><p><strong>数据：</strong> 2026年5月 A股日均成交额 2.66 万亿元，较2025年增长50%以上<br><strong>结论：</strong> 当前市场交投活跃，非地量区间</p><h3 id="_2-持仓继续下跌-10-20-估值跌至历史极端低位" tabindex="-1">② 持仓继续下跌 10%-20%，估值跌至历史极端低位 <a class="header-anchor" href="#_2-持仓继续下跌-10-20-估值跌至历史极端低位" aria-label="Permalink to &quot;② 持仓继续下跌 10%-20%，估值跌至历史极端低位&quot;">​</a></h3><p><strong>状态：</strong> ⚠️ 接近中</p><p><strong>数据：</strong></p><ul><li>小米距52周高点 -61.24%，距52周低点仅 +1.28%（<strong>已接近历史低位</strong>）</li><li>阿里距52周高点 -44.14%，距52周低点 +2.61%</li><li>恒科ETF距52周低点仅 +1.75%</li></ul><p><strong>结论：</strong> 恒生科技估值已接近历史极端低位，小米几乎触及52周最低，恒科ETF亦然</p><h3 id="_3-强势股-如白酒-开始补跌" tabindex="-1">③ 强势股（如白酒）开始补跌 <a class="header-anchor" href="#_3-强势股-如白酒-开始补跌" aria-label="Permalink to &quot;③ 强势股（如白酒）开始补跌&quot;">​</a></h3><p><strong>状态：</strong> ✅ <strong>显著出现</strong></p><p><strong>数据：</strong></p><ul><li>五粮液今日暴跌 <strong>-27.74%</strong>，52周从 129.27 跌至 76.55，跌幅 <strong>-37.88%</strong></li><li>茅台今日下跌 <strong>-9.86%</strong>，52周从 1568 跌至 1241，跌幅 <strong>-15.89%</strong></li><li>中酒协报告：86.7% 白酒企业利润下滑，商务礼赠场景减少 82.8%</li></ul><p><strong>结论：</strong> 白酒板块崩跌，五粮液单日暴跌近28%，这是极其显著的强势股补跌信号</p><h3 id="_4-周围没有人再谈股票" tabindex="-1">④ 周围没有人再谈股票 <a class="header-anchor" href="#_4-周围没有人再谈股票" aria-label="Permalink to &quot;④ 周围没有人再谈股票&quot;">​</a></h3><p><strong>状态：</strong> ❌ 未出现</p><p><strong>数据：</strong> 2026年5月新增开户 276.53 万户，同比暴增 77.76%，A股投资者总数已超 2.5 亿<br><strong>结论：</strong> 市场情绪仍活跃，新增资金持续入场，&quot;无人谈股&quot;信号未出现</p><h3 id="_5-机构割肉消费追-ai-的新闻刷屏" tabindex="-1">⑤ 机构割肉消费追 AI 的新闻刷屏 <a class="header-anchor" href="#_5-机构割肉消费追-ai-的新闻刷屏" aria-label="Permalink to &quot;⑤ 机构割肉消费追 AI 的新闻刷屏&quot;">​</a></h3><p><strong>状态：</strong> ✅ <strong>明确出现</strong></p><p><strong>数据：</strong></p><ul><li>白酒行业被机构认为处于&quot;深度调整&quot;和&quot;困境&quot;阶段（中酒协报告）</li><li>资金从消费流出，聚焦科技成长：光模块、PCB、AI芯片、存储芯片等细分赛道表现抢眼</li><li>五粮液会计差错更正，营收下调50%，净利润下调70%</li></ul><p><strong>结论：</strong> 机构正在大规模调仓，从消费切换到科技成长，白酒被抛弃</p><h3 id="_6-国家队毫无动静-突然出手增持的那一天" tabindex="-1">⑥ 国家队毫无动静，突然出手增持的那一天 <a class="header-anchor" href="#_6-国家队毫无动静-突然出手增持的那一天" aria-label="Permalink to &quot;⑥ 国家队毫无动静，突然出手增持的那一天&quot;">​</a></h3><p><strong>状态：</strong> ❌ 未出现</p><p><strong>数据：</strong></p><ul><li>智谱（02513.HK）6月22日市值突破万亿港元，6月8日纳入恒生科技指数和港股通</li><li>南向资金连续4天净买入智谱</li><li>但未见国家队增持恒生科技的明确新闻</li></ul><p><strong>结论：</strong> 等待国家队信号</p><hr><h2 id="信号汇总" tabindex="-1">信号汇总 <a class="header-anchor" href="#信号汇总" aria-label="Permalink to &quot;信号汇总&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>信号</th><th>状态</th><th>说明</th></tr></thead><tbody><tr><td>①</td><td>成交地量</td><td>❌</td><td>成交活跃，非地量</td></tr><tr><td>②</td><td>估值极端低位</td><td>⚠️</td><td>接近历史低位（恒科+小米近52周低）</td></tr><tr><td>③</td><td>强势股补跌</td><td>✅</td><td>白酒崩跌，五粮液-28%，茅台-10%</td></tr><tr><td>④</td><td>无人谈股</td><td>❌</td><td>开户数同比+78%，创新高</td></tr><tr><td>⑤</td><td>机构割肉</td><td>✅</td><td>消费→AI调仓，新闻刷屏</td></tr><tr><td>⑥</td><td>国家队增持</td><td>❌</td><td>等待信号</td></tr></tbody></table><p><strong>当前进度：2/6 触发，2/6 接近中</strong></p><hr><h2 id="今日重点-白酒崩跌的意义" tabindex="-1">今日重点：白酒崩跌的意义 <a class="header-anchor" href="#今日重点-白酒崩跌的意义" aria-label="Permalink to &quot;今日重点：白酒崩跌的意义&quot;">​</a></h2><p>今天的白酒走势值得重点记录：</p><p><strong>五粮液单日暴跌 -27.74%</strong>，这是一个极其罕见的跌幅。消息面上：</p><ul><li>公司会计差错更正，2025年前三季度营收从 609 亿下调到 306 亿（-50%）</li><li>净利润从 153.67 亿下调到 44.16 亿（-71%）</li><li>董事长被留置调查，管理层真空两个月</li><li>经销商渠道库存高达 6 个月，批发价倒挂</li></ul><p>这不是普通的&quot;补跌&quot;，而是<strong>基本面崩塌</strong>驱动的暴跌。</p><p>从历史经验看，当白酒这种&quot;确定性&quot;资产开始崩塌时，往往意味着市场情绪已经极度悲观。但这是否就是底部信号？</p><p><strong>需要观察：</strong> 这种崩塌是&quot;最后一跌&quot;还是&quot;下跌中继&quot;？</p><hr><h2 id="操作建议" tabindex="-1">操作建议 <a class="header-anchor" href="#操作建议" aria-label="Permalink to &quot;操作建议&quot;">​</a></h2><table tabindex="0"><thead><tr><th>原则</th><th>说明</th></tr></thead><tbody><tr><td>不割肉</td><td>恒科估值已接近历史低位，不在此处砍仓</td></tr><tr><td>不补仓</td><td>等待更明确的底部信号</td></tr><tr><td>观察白酒</td><td>白酒崩跌是否扩散到其他消费板块</td></tr><tr><td>记录信号</td><td>每日对照 6 个信号，观察进度</td></tr></tbody></table><hr><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><blockquote><p>当前 2/6 信号已触发，但 ①（地量）和 ⑥（国家队）尚未出现。</p><p>如果恒生科技继续下跌 10%，小米触及 52 周低点 23.52，你的持仓心态还扛得住吗？</p></blockquote><p>历史上每一次极致信号出现后，都对应着一次均值回归。但这个过程有多长、有多深，没有人能提前知道。</p><p><strong>耐心是一种能力，不是一种情绪。</strong></p><hr><h2 id="附-关键数据来源" tabindex="-1">附：关键数据来源 <a class="header-anchor" href="#附-关键数据来源" aria-label="Permalink to &quot;附：关键数据来源&quot;">​</a></h2><ul><li>A股成交额：中酒协报告，2026年5月日均 2.66 万亿元</li><li>新开户数据：上交所，2026年5月 276.53 万户</li><li>白酒数据：中酒协《2026中国白酒市场中期研究报告》</li><li>股价数据：腾讯财经实时行情</li></ul><hr><p><em>每日信号监测将持续更新。</em></p>',70)])])}const b=r(e,[["render",l]]);export{p as __pageData,b as default};
